     1→/**
     2→ * Link Library Page
     3→ *
     4→ * Full-featured bookmark management system with:
     5→ * - Import/Export (Netscape HTML format)
     6→ * - Collections for organization
     7→ * - AI-powered categorization
     8→ * - Search and filter
     9→ * - Grid/List view toggle
    10→ */
    11→
    12→import React, { useState, useCallback, useMemo } from 'react';
    13→import { PageHeader } from '../components/PageHeader';
    14→import { CollectionSidebar } from '../components/CollectionSidebar';
    15→import { useLinkLibraryStore, type Link } from '../stores/useLinkLibraryStore';
    16→import {
    17→  parseNetscapeBookmarks,
    18→  convertToLinks,
    19→  readFileAsText,
    20→  isValidBookmarkFile,
    21→} from '../utils/bookmarkParser';
    22→import { exportAndDownload } from '../utils/bookmarkExporter';
    23→
    24→export const LinkLibrary: React.FC = () => {
    25→  const {
    26→    links,
    27→    collections,
    28→    viewMode,
    29→    sortField,
    30→    sortDirection,
    31→    searchQuery,
    32→    activeCollectionId,
    33→    selectedLinkIds,
    34→    setViewMode,
    35→    setSortField,
    36→    setSortDirection,
    37→    setSearchQuery,
    38→    toggleLinkSelection,
    39→    selectAllLinks,
    40→    clearSelection,
    41→    deleteLinks,
    42→    toggleFavorite,
    43→    toggleArchived,
    44→    importLinks,
    45→    getAllLinks,
    46→    getLinksInCollection,
    47→    getFavoriteLinks,
    48→    searchLinks,
    49→  } = useLinkLibraryStore();
    50→
    51→  const [isImporting, setIsImporting] = useState(false);
    52→  const [importError, setImportError] = useState<string | null>(null);
    53→  const [importStats, setImportStats] = useState<{ total: number; imported: number } | null>(null);
    54→  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
    55→
    56→  // Get archived links
    57→  const getArchivedLinks = useCallback(() => {
    58→    return Object.values(links).filter((link) => link.isArchived);
    59→  }, [links]);
    60→
    61→  // Get filtered and sorted links
    62→  const displayedLinks = useMemo(() => {
    63→    let result: Link[];
    64→
    65→    // Filter by collection or view
    66→    if (activeCollectionId === 'favorites') {
    67→      result = getFavoriteLinks();
    68→    } else if (activeCollectionId === 'archived') {
    69→      result = getArchivedLinks();
    70→    } else if (activeCollectionId) {
    71→      result = getLinksInCollection(activeCollectionId);
    72→    } else if (searchQuery) {
    73→      result = searchLinks(searchQuery);
    74→    } else {
    75→      result = getAllLinks();
    76→    }
    77→
    78→    // Sort
    79→    result = [...result].sort((a, b) => {
    80→      let comparison = 0;
    81→      switch (sortField) {
    82→        case 'title':
    83→          comparison = a.title.localeCompare(b.title);
    84→          break;
    85→        case 'createdAt':
    86→          comparison = a.createdAt.getTime() - b.createdAt.getTime();
    87→          break;
    88→        case 'updatedAt':
    89→          comparison = a.updatedAt.getTime() - b.updatedAt.getTime();
    90→          break;
    91→        case 'visitCount':
    92→          comparison = a.visitCount - b.visitCount;
    93→          break;
    94→      }
    95→      return sortDirection === 'asc' ? comparison : -comparison;
    96→    });
    97→
    98→    return result;
    99→  }, [
   100→    activeCollectionId,
   101→    searchQuery,
   102→    sortField,
   103→    sortDirection,
   104→    getAllLinks,
   105→    getLinksInCollection,
   106→    getFavoriteLinks,
   107→    getArchivedLinks,
   108→    searchLinks,
   109→  ]);
   110→
   111→  // Handle file import
   112→  const handleFileImport = useCallback(
   113→    async (file: File) => {
   114→      setIsImporting(true);
   115→      setImportError(null);
   116→      setImportStats(null);
   117→
   118→      try {
   119→        const content = await readFileAsText(file);
   120→
   121→        if (!isValidBookmarkFile(content)) {
   122→          throw new Error('Invalid bookmark file format. Please export bookmarks from your browser.');
   123→        }
   124→
   125→        const result = parseNetscapeBookmarks(content);
   126→        const linksToImport = convertToLinks(result.bookmarks);
   127→        const imported = importLinks(linksToImport);
   128→
   129→        setImportStats({
   130→          total: result.stats.total,
   131→          imported: imported.length,
   132→        });
   133→      } catch (error) {
   134→        setImportError(error instanceof Error ? error.message : 'Failed to import bookmarks');
   135→      } finally {
   136→        setIsImporting(false);
   137→      }
   138→    },
   139→    [importLinks]
   140→  );
   141→
   142→  // Handle drag and drop
   143→  const handleDrop = useCallback(
   144→    (e: React.DragEvent) => {
   145→      e.preventDefault();
   146→      const file = e.dataTransfer.files[0];
   147→      if (file && (file.name.endsWith('.html') || file.name.endsWith('.htm'))) {
   148→        handleFileImport(file);
   149→      } else {
   150→        setImportError('Please drop a valid HTML bookmark file');
   151→      }
   152→    },
   153→    [handleFileImport]
   154→  );
   155→
   156→  const handleDragOver = (e: React.DragEvent) => {
   157→    e.preventDefault();
   158→  };
   159→
   160→  // Handle file input
   161→  const handleFileInput = useCallback(
   162→    (e: React.ChangeEvent<HTMLInputElement>) => {
   163→      const file = e.target.files?.[0];
   164→      if (file) {
   165→        handleFileImport(file);
   166→      }
   167→    },
   168→    [handleFileImport]
   169→  );
   170→
   171→  // Handle bulk delete
   172→  const handleBulkDelete = useCallback(() => {
   173→    if (selectedLinkIds.size > 0) {
   174→      deleteLinks(Array.from(selectedLinkIds));
   175→      clearSelection();
   176→    }
   177→  }, [selectedLinkIds, deleteLinks, clearSelection]);
   178→
   179→  // Handle export
   180→  const handleExport = useCallback(() => {
   181→    const allLinks = getAllLinks();
   182→    if (allLinks.length === 0) {
   183→      return;
   184→    }
   185→    exportAndDownload(allLinks, {
   186→      title: 'Link Library Export',
   187→      groupByCategory: true,
   188→    });
   189→  }, [getAllLinks]);
   190→
   191→  // Handle select all
   192→  const handleSelectAll = useCallback(() => {
   193→    if (selectedLinkIds.size === displayedLinks.length) {
   194→      clearSelection();
   195→    } else {
   196→      selectAllLinks(displayedLinks.map((l) => l.id));
   197→    }
   198→  }, [selectedLinkIds.size, displayedLinks, selectAllLinks, clearSelection]);
   199→
   200→  const linkCount = Object.keys(links).length;
   201→  const collectionCount = Object.keys(collections).length;
   202→
   203→  return (
   204→    <div className="flex-1 flex min-h-0">
   205→      {/* Collection Sidebar */}
   206→      <CollectionSidebar
   207→        isCollapsed={isSidebarCollapsed}
   208→        onToggleCollapse={() => setIsSidebarCollapsed(!isSidebarCollapsed)}
   209→      />
   210→
   211→      {/* Main Content */}
   212→      <div className="flex-1 flex flex-col min-h-0 p-4 sm:p-6 lg:p-8">
   213→        <PageHeader title="Link Library" subtitle="Manage your bookmarks and collections" />
   214→
   215→      {/* Stats Bar */}
   216→      <div className="flex items-center gap-4 mb-6 text-sm text-text-light-secondary dark:text-text-dark-secondary">
   217→        <span>{linkCount} links</span>
   218→        <span>•</span>
   219→        <span>{collectionCount} collections</span>
   220→        {selectedLinkIds.size > 0 && (
   221→          <>
   222→            <span>•</span>
   223→            <span className="text-accent-blue">{selectedLinkIds.size} selected</span>
   224→          </>
   225→        )}
   226→      </div>
   227→
   228→      {/* Action Bar */}
   229→      <div className="flex flex-wrap items-center gap-4 mb-6">
   230→        {/* Search */}
   231→        <div className="flex-1 min-w-[200px] max-w-md">
   232→          <input
   233→            type="text"
   234→            value={searchQuery}
   235→            onChange={(e) => setSearchQuery(e.target.value)}
   236→            placeholder="Search links..."
   237→            className="w-full px-4 py-2 rounded-button border border-border-light dark:border-border-dark
   238→                       bg-white dark:bg-surface-dark
   239→                       text-text-light-primary dark:text-text-dark-primary
   240→                       focus:outline-none focus:ring-2 focus:ring-accent-blue"
   241→          />
   242→        </div>
   243→
   244→        {/* View Toggle */}
   245→        <div className="flex items-center gap-1 p-1 rounded-button bg-neutral-100 dark:bg-neutral-800">
   246→          <button
   247→            onClick={() => setViewMode('grid')}
   248→            className={`px-3 py-1.5 rounded text-sm font-medium transition-colors ${viewMode === 'grid'
   249→                ? 'bg-white dark:bg-surface-dark shadow-sm text-text-light-primary dark:text-text-dark-primary'
   250→                : 'text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary'
   251→              }`}
   252→          >
   253→            Grid
   254→          </button>
   255→          <button
   256→            onClick={() => setViewMode('list')}
   257→            className={`px-3 py-1.5 rounded text-sm font-medium transition-colors ${viewMode === 'list'
   258→                ? 'bg-white dark:bg-surface-dark shadow-sm text-text-light-primary dark:text-text-dark-primary'
   259→                : 'text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary'
   260→              }`}
   261→          >
   262→            List
   263→          </button>
   264→        </div>
   265→
   266→        {/* Sort */}
   267→        <select
   268→          value={sortField}
   269→          onChange={(e) => setSortField(e.target.value as typeof sortField)}
   270→          className="px-3 py-2 rounded-button border border-border-light dark:border-border-dark
   271→                     bg-white dark:bg-surface-dark
   272→                     text-text-light-primary dark:text-text-dark-primary text-sm"
   273→        >
   274→          <option value="createdAt">Date Added</option>
   275→          <option value="updatedAt">Last Updated</option>
   276→          <option value="title">Title</option>
   277→          <option value="visitCount">Most Visited</option>
   278→        </select>
   279→
   280→        <button
   281→          onClick={() => setSortDirection(sortDirection === 'asc' ? 'desc' : 'asc')}
   282→          className="p-2 rounded-button border border-border-light dark:border-border-dark
   283→                     bg-white dark:bg-surface-dark hover:bg-neutral-50 dark:hover:bg-neutral-800
   284→                     transition-colors"
   285→          title={sortDirection === 'asc' ? 'Sort Descending' : 'Sort Ascending'}
   286→        >
   287→          {sortDirection === 'asc' ? '↑' : '↓'}
   288→        </button>
   289→
   290→        {/* Import Button */}
   291→        <label className="px-4 py-2 bg-accent-blue hover:bg-accent-blue-hover text-white rounded-button
   292→                         text-sm font-medium cursor-pointer transition-colors">
   293→          Import
   294→          <input
   295→            type="file"
   296→            accept=".html,.htm"
   297→            onChange={handleFileInput}
   298→            className="hidden"
   299→          />
   300→        </label>
   301→
   302→        {/* Export Button */}
   303→        {linkCount > 0 && (
   304→          <button
   305→            onClick={handleExport}
   306→            className="px-4 py-2 bg-neutral-100 dark:bg-neutral-800 hover:bg-neutral-200 dark:hover:bg-neutral-700
   307→                       text-text-light-primary dark:text-text-dark-primary rounded-button
   308→                       text-sm font-medium transition-colors"
   309→          >
   310→            Export
   311→          </button>
   312→        )}
   313→
   314→        {/* Bulk Actions (when items selected) */}
   315→        {selectedLinkIds.size > 0 && (
   316→          <button
   317→            onClick={handleBulkDelete}
   318→            className="px-4 py-2 bg-status-error hover:bg-red-600 text-white rounded-button
   319→                       text-sm font-medium transition-colors"
   320→          >
   321→            Delete ({selectedLinkIds.size})
   322→          </button>
   323→        )}
   324→      </div>
   325→
   326→      {/* Import Status */}
   327→      {(importError || importStats) && (
   328→        <div
   329→          className={`mb-6 p-4 rounded-button ${importError
   330→              ? 'bg-status-error/10 border border-status-error text-status-error'
   331→              : 'bg-status-success/10 border border-status-success text-status-success'
   332→            }`}
   333→        >
   334→          {importError ? (
   335→            <p>{importError}</p>
   336→          ) : importStats ? (
   337→            <p>
   338→              Successfully imported {importStats.imported} of {importStats.total} bookmarks!
   339→            </p>
   340→          ) : null}
   341→          <button
   342→            onClick={() => {
   343→              setImportError(null);
   344→              setImportStats(null);
   345→            }}
   346→            className="mt-2 text-sm underline"
   347→          >
   348→            Dismiss
   349→          </button>
   350→        </div>
   351→      )}
   352→
   353→      {/* Main Content */}
   354→      {displayedLinks.length === 0 ? (
   355→        /* Empty State / Drop Zone */
   356→        <div
   357→          onDrop={handleDrop}
   358→          onDragOver={handleDragOver}
   359→          className="flex-1 flex flex-col items-center justify-center p-8
   360→                     border-2 border-dashed border-border-light dark:border-border-dark rounded-card
   361→                     bg-surface-light dark:bg-surface-dark-elevated"
   362→        >
   363→          {isImporting ? (
   364→            <div className="flex flex-col items-center gap-4">
   365→              <div className="w-12 h-12 border-4 border-accent-blue border-t-transparent rounded-full animate-spin" />
   366→              <p className="text-text-light-secondary dark:text-text-dark-secondary">
   367→                Importing bookmarks...
   368→              </p>
   369→            </div>
   370→          ) : (
   371→            <>
   372→              <span className="text-6xl mb-4">🔗</span>
   373→              <h3 className="text-xl font-semibold text-text-light-primary dark:text-text-dark-primary mb-2">
   374→                {searchQuery ? 'No links found' : 'No links yet'}
   375→              </h3>
   376→              <p className="text-text-light-secondary dark:text-text-dark-secondary text-center max-w-md mb-6">
   377→                {searchQuery
   378→                  ? `No links match "${searchQuery}"`
   379→                  : 'Import your browser bookmarks or add links manually to get started.'}
   380→              </p>
   381→              {!searchQuery && (
   382→                <div className="flex flex-col items-center gap-2">
   383→                  <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
   384→                    Drag and drop a bookmark HTML file here, or
   385→                  </p>
   386→                  <label className="px-6 py-3 bg-accent-blue hover:bg-accent-blue-hover text-white rounded-button
   387→                                   text-base font-medium cursor-pointer transition-colors">
   388→                    Choose File
   389→                    <input
   390→                      type="file"
   391→                      accept=".html,.htm"
   392→                      onChange={handleFileInput}
   393→                      className="hidden"
   394→                    />
   395→                  </label>
   396→                </div>
   397→              )}
   398→            </>
   399→          )}
   400→        </div>
   401→      ) : (
   402→        /* Links Grid/List */
   403→        <div className="flex-1 overflow-y-auto">
   404→          {/* Select All Checkbox */}
   405→          <div className="flex items-center gap-2 mb-4">
   406→            <input
   407→              type="checkbox"
   408→              checked={selectedLinkIds.size === displayedLinks.length && displayedLinks.length > 0}
   409→              onChange={handleSelectAll}
   410→              className="w-4 h-4 rounded border-border-light dark:border-border-dark"
   411→            />
   412→            <span className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
   413→              Select All
   414→            </span>
   415→          </div>
   416→
   417→          {viewMode === 'grid' ? (
   418→            /* Grid View */
   419→            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
   420→              {displayedLinks.map((link) => (
   421→                <LinkCard
   422→                  key={link.id}
   423→                  link={link}
   424→                  isSelected={selectedLinkIds.has(link.id)}
   425→                  onToggleSelect={() => toggleLinkSelection(link.id)}
   426→                  onToggleFavorite={() => toggleFavorite(link.id)}
   427→                  onToggleArchive={() => toggleArchived(link.id)}
   428→                />
   429→              ))}
   430→            </div>
   431→          ) : (
   432→            /* List View */
   433→            <div className="space-y-2">
   434→              {displayedLinks.map((link) => (
   435→                <LinkListItem
   436→                  key={link.id}
   437→                  link={link}
   438→                  isSelected={selectedLinkIds.has(link.id)}
   439→                  onToggleSelect={() => toggleLinkSelection(link.id)}
   440→                  onToggleFavorite={() => toggleFavorite(link.id)}
   441→                  onToggleArchive={() => toggleArchived(link.id)}
   442→                />
   443→              ))}
   444→            </div>
   445→          )}
   446→        </div>
   447→      )}
   448→      </div>
   449→    </div>
   450→  );
   451→};
   452→
   453→// ============================================================================
   454→// Link Card Component (Grid View)
   455→// ============================================================================
   456→
   457→interface LinkCardProps {
   458→  link: Link;
   459→  isSelected: boolean;
   460→  onToggleSelect: () => void;
   461→  onToggleFavorite: () => void;
   462→  onToggleArchive: () => void;
   463→}
   464→
   465→const LinkCard: React.FC<LinkCardProps> = ({
   466→  link,
   467→  isSelected,
   468→  onToggleSelect,
   469→  onToggleFavorite,
