   486→      <div className="flex items-start gap-3 mb-3">
   487→        <input
   488→          type="checkbox"
   489→          checked={isSelected}
   490→          onChange={onToggleSelect}
   491→          className="mt-1 w-4 h-4 rounded border-border-light dark:border-border-dark"
   492→        />
   493→        <img
   494→          src={faviconUrl}
   495→          alt=""
   496→          className="w-6 h-6 rounded flex-shrink-0"
   497→          onError={(e) => {
   498→            (e.target as HTMLImageElement).src = 'data:image/svg+xml,<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="%236b7280"><path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm-1 17.93c-3.95-.49-7-3.85-7-7.93 0-.62.08-1.21.21-1.79L9 15v1c0 1.1.9 2 2 2v1.93zm6.9-2.54c-.26-.81-1-1.39-1.9-1.39h-1v-3c0-.55-.45-1-1-1H8v-2h2c.55 0 1-.45 1-1V7h2c1.1 0 2-.9 2-2v-.41c2.93 1.19 5 4.06 5 7.41 0 2.08-.8 3.97-2.1 5.39z"/></svg>';
   499→          }}
   500→        />
