   522→              {link.category}
   523→            </span>
   524→          )}
   525→          {link.tags.slice(0, 2).map((tag) => (
   526→            <span
   527→              key={tag}
   528→              className="px-2 py-0.5 text-xs rounded-full bg-neutral-100 dark:bg-neutral-800
   529→                         text-text-light-secondary dark:text-text-dark-secondary"
   530→            >
   531→              {tag}
   532→            </span>
   533→          ))}
   534→          {link.tags.length > 2 && (
   535→            <span className="px-2 py-0.5 text-xs text-text-light-secondary dark:text-text-dark-secondary">
   536→              +{link.tags.length - 2}
   537→            </span>
   538→          )}
   539→        </div>
   540→      )}
   541→
   542→      {/* Actions */}
   543→      <div className="flex items-center gap-2 pt-2 border-t border-border-light dark:border-border-dark">
   544→        <button
   545→          onClick={onToggleFavorite}
   546→          className={`p-1.5 rounded transition-colors ${link.isFavorite
   547→              ? 'text-status-warning'
   548→              : 'text-text-light-secondary dark:text-text-dark-secondary hover:text-status-warning'
   549→            }`}
   550→          title={link.isFavorite ? 'Remove from favorites' : 'Add to favorites'}
