   567→    </div>
   568→  );
   569→};
   570→
   571→// ============================================================================
   572→// Link List Item Component (List View)
   573→// ============================================================================
   574→
   575→const LinkListItem: React.FC<LinkCardProps> = ({
   576→  link,
   577→  isSelected,
   578→  onToggleSelect,
   579→  onToggleFavorite,
   580→  onToggleArchive,
   581→}) => {
   582→  const faviconUrl = `https://www.google.com/s2/favicons?domain=${new URL(link.url).hostname}&sz=16`;
   583→
   584→  return (
   585→    <div
   586→      className={`
   587→        flex items-center gap-4 px-4 py-3 rounded-button
   588→        bg-surface-light dark:bg-surface-dark-elevated
   589→        border transition-all duration-200
   590→        ${isSelected
   591→          ? 'border-accent-blue ring-2 ring-accent-blue/20'
   592→          : 'border-border-light dark:border-border-dark hover:border-accent-blue/50'
   593→        }
   594→      `}
   595→    >
   596→      <input
