   643→      </button>
   644→
   645→      <button
   646→        onClick={onToggleArchive}
   647→        className="p-1.5 rounded text-text-light-secondary dark:text-text-dark-secondary
   648→                   hover:text-text-light-primary dark:hover:text-text-dark-primary transition-colors"
   649→        title={link.isArchived ? 'Unarchive' : 'Archive'}
   650→      >
