     9→
    10→import React, { useEffect, useState, useRef, useMemo } from 'react';
    11→import { motion, AnimatePresence } from 'framer-motion';
    12→import { useNotesStore } from '../stores/useNotesStore';
    13→import { useFoldersStore } from '../stores/useFoldersStore';
    14→import { NotesEditor, NotesEditorEmpty } from '../widgets/NotesEditor';
    15→import { ConfirmDialog } from '../components/ConfirmDialog';
    16→import { PromptDialog } from '../components/PromptDialog';
    17→import { PageHeader } from '../components/PageHeader';
    18→import { useUndoStore } from '../stores/useUndoStore';
    19→import { exportNoteToMarkdown } from '../services/noteExport';
    20→import { exportNoteToPDF } from '../services/notePdfExport';
    21→import { logger } from '../services/logger';
    22→import type { Note } from '../types/notes';
    23→
    24→const log = logger.module('Notes');
    25→
    26→/**
    27→ * Recursive Folder Tree Node Component
    28→ */
    29→interface FolderTreeNodeProps {
    30→  node: any;
    31→  depth: number;
    32→  activeFolderId: string | null;
    33→  expandedFolderIds: Set<string>;
    34→  onSelect: (id: string) => void;
    35→  onToggleExpanded: (id: string) => void;
    36→  onDelete: (id: string, name: string) => void;
    37→  onRename: (id: string, name: string) => void;
    38→  getFolderNoteCount: (id: string) => number;
    39→}
    40→
    41→const FolderTreeNode: React.FC<FolderTreeNodeProps> = ({
    42→  node,
    43→  depth,
    44→  activeFolderId,
    45→  expandedFolderIds,
    46→  onSelect,
    47→  onToggleExpanded,
    48→  onDelete,
    49→  onRename,
    50→  getFolderNoteCount,
    51→}) => {
    52→  const isExpanded = expandedFolderIds.has(node.id);
    53→  const hasChildren = node.children && node.children.length > 0;
    54→  const noteCount = getFolderNoteCount(node.id);
    55→
    56→  return (
    57→    <div>
    58→      <div
    59→        className={`group relative rounded-lg transition-colors ${
    60→          activeFolderId === node.id
    61→            ? 'bg-primary-cyan bg-opacity-10'
    62→            : 'hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated'
    63→        }`}
    64→        style={{ paddingLeft: `${depth * 16}px` }}
    65→      >
    66→        <div className="flex items-center">
    67→          {/* Expand/collapse button */}
    68→          {hasChildren && (
    69→            <button
    70→              onClick={(e) => {
    71→                e.stopPropagation();
    72→                onToggleExpanded(node.id);
    73→              }}
    74→              className="p-1 hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated rounded transition-colors"
    75→            >
    76→              <span className="text-sm">{isExpanded ? '▼' : '▶'}</span>
    77→            </button>
    78→          )}
    79→          {!hasChildren && <span className="w-6" />}
    80→
    81→          {/* Folder button */}
    82→          <button
    83→            onClick={() => onSelect(node.id)}
    84→            className={`flex-1 text-left px-3 py-2 transition-colors flex items-center gap-2 ${
    85→              activeFolderId === node.id
    86→                ? 'text-primary-cyan font-medium'
    87→                : 'text-text-light-secondary dark:text-text-dark-secondary'
    88→            }`}
    89→          >
    90→            <span>{hasChildren ? (isExpanded ? '📂' : '📁') : '📄'}</span>
    91→            <span>{node.name}</span>
    92→            {noteCount > 0 && (
    93→              <span className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
    94→                ({noteCount})
    95→              </span>
    96→            )}
    97→          </button>
    98→
    99→          {/* Action buttons */}
   100→          <div className="absolute right-2 opacity-0 group-hover:opacity-100 flex gap-1 transition-opacity">
   101→            <button
   102→              onClick={(e) => {
   103→                e.stopPropagation();
   104→                onRename(node.id, node.name);
   105→              }}
   106→              className="p-1 hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated rounded transition-colors"
   107→              title="Rename folder"
   108→            >
   109→              ✏️
   110→            </button>
   111→            <button
   112→              onClick={(e) => {
   113→                e.stopPropagation();
   114→                onDelete(node.id, node.name);
   115→              }}
   116→              className="p-1 hover:bg-red-100 dark:hover:bg-red-900 rounded text-red-600 transition-colors"
   117→              title="Delete folder"
   118→            >
   119→              🗑️
   120→            </button>
   121→          </div>
   122→        </div>
   123→      </div>
   124→
   125→      {/* Children */}
   126→      {isExpanded && hasChildren && (
   127→        <div className="ml-4">
   128→          {node.children.map((child: any) => (
   129→            <FolderTreeNode
   130→              key={child.id}
   131→              node={child}
   132→              depth={depth + 1}
   133→              activeFolderId={activeFolderId}
   134→              expandedFolderIds={expandedFolderIds}
   135→              onSelect={onSelect}
   136→              onToggleExpanded={onToggleExpanded}
   137→              onDelete={onDelete}
   138→              onRename={onRename}
   139→              getFolderNoteCount={getFolderNoteCount}
   140→            />
   141→          ))}
   142→        </div>
   143→      )}
   144→    </div>
   145→  );
   146→};
   147→
   148→/**
   149→ * Folder Sidebar Component (Simplified for MVP)
   150→ */
   151→const FolderSidebar: React.FC = () => {
   152→  // Get raw folders object (stable reference unless folders change)
   153→  const foldersObj = useFoldersStore((state) => state.folders);
   154→  const activeFolderId = useFoldersStore((state) => state.activeFolderId);
   155→  const setActiveFolder = useFoldersStore((state) => state.setActiveFolder);
   156→  const createFolder = useFoldersStore((state) => state.createFolder);
   157→  const deleteFolder = useFoldersStore((state) => state.deleteFolder);
   158→  const updateFolder = useFoldersStore((state) => state.updateFolder);
   159→  const notesObj = useNotesStore((state) => state.notes);
   160→  const searchNotes = useNotesStore((state) => state.searchNotes);
   161→
   162→  // Dialog state
   163→  const [deleteDialogOpen, setDeleteDialogOpen] = useState(false);
   164→  const [renameDialogOpen, setRenameDialogOpen] = useState(false);
   165→  const [selectedFolderId, setSelectedFolderId] = useState<string | null>(null);
   166→  const [selectedFolderName, setSelectedFolderName] = useState('');
   167→
   168→  // Search state
   169→  const [searchQuery, setSearchQuery] = useState('');
   170→  const searchInputRef = useRef<HTMLInputElement>(null);
   171→
   172→  // Keyboard shortcut for search (Cmd+K)
   173→  useEffect(() => {
   174→    const handleKeyDown = (e: KeyboardEvent) => {
   175→      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
   176→        e.preventDefault();
   177→        searchInputRef.current?.focus();
   178→      }
   179→    };
   180→
   181→    window.addEventListener('keydown', handleKeyDown);
   182→    return () => window.removeEventListener('keydown', handleKeyDown);
   183→  }, []);
   184→
   185→  // Get tree structure for nested folders
   186→  const getTree = useFoldersStore((state) => state.getTree);
   187→  const toggleExpanded = useFoldersStore((state) => state.toggleExpanded);
   188→  const expandedFolderIds = useFoldersStore((state) => state.expandedFolderIds);
   189→
   190→  const folderTree = useMemo(() => getTree(), [foldersObj, getTree]);
   191→
   192→  // Get note count for a folder
   193→  const getFolderNoteCount = (folderId: string) => {
   194→    return Object.values(notesObj).filter(note => note.folderId === folderId).length;
   195→  };
   196→
   197→  // Handle folder deletion
   198→  const handleDeleteFolder = (folderId: string, folderName: string) => {
   199→    setSelectedFolderId(folderId);
   200→    setSelectedFolderName(folderName);
   201→    setDeleteDialogOpen(true);
   202→  };
   203→
   204→  const confirmDeleteFolder = () => {
   205→    if (!selectedFolderId) return;
   206→
   207→    // Save folder and notes for undo
   208→    const folderToDelete = foldersObj[selectedFolderId];
   209→    if (!folderToDelete) {
   210→      log.warn('Folder not found', { folderId: selectedFolderId });
   211→      return;
   212→    }
   213→
   214→    const notesToDelete = Object.values(notesObj).filter(note => note.folderId === selectedFolderId);
   215→    const noteCount = notesToDelete.length;
   216→
   217→    // Delete all notes in this folder (without undo since folder undo will handle it)
   218→    // We need to temporarily bypass the undo system for individual notes
   219→    notesToDelete.forEach(note => {
   220→      // Call the store action directly without triggering undo
   221→      useNotesStore.setState((state) => {
   222→        const { [note.id]: deleted, ...remainingNotes } = state.notes;
   223→        return {
   224→          notes: remainingNotes,
   225→          activeNoteId: state.activeNoteId === note.id ? null : state.activeNoteId,
   226→        };
   227→      });
   228→    });
   229→
   230→    // Delete the folder
   231→    deleteFolder(selectedFolderId);
   232→
   233→    log.info(`Folder "${folderToDelete.name}" deleted`, { noteCount });
   234→
   235→    // Add undo action to restore folder AND notes
   236→    useUndoStore.getState().addUndoAction(
   237→      `Folder "${folderToDelete.name}" and ${noteCount} note(s) deleted`,
   238→      () => {
   239→        // Restore the folder
   240→        useFoldersStore.setState((state) => ({
   241→          folders: {
   242→            ...state.folders,
   243→            [folderToDelete.id]: folderToDelete,
   244→          },
   245→        }));
   246→
   247→        // Restore all notes
   248→        useNotesStore.setState((state) => {
   249→          const restoredNotes = { ...state.notes };
   250→          notesToDelete.forEach(note => {
   251→            restoredNotes[note.id] = note;
   252→          });
   253→          return {
   254→            notes: restoredNotes,
   255→          };
   256→        });
   257→
   258→        log.info(`Folder "${folderToDelete.name}" and ${noteCount} note(s) restored (undo)`);
   259→      }
   260→    );
   261→  };
   262→
   263→  // Handle folder rename
   264→  const handleRenameFolder = (folderId: string, currentName: string) => {
   265→    setSelectedFolderId(folderId);
   266→    setSelectedFolderName(currentName);
   267→    setRenameDialogOpen(true);
   268→  };
   269→
   270→  const confirmRenameFolder = (newName: string) => {
   271→    if (!selectedFolderId || !newName.trim()) return;
   272→    updateFolder(selectedFolderId, { name: newName.trim() });
   273→  };
   274→
   275→  return (
   276→    <div className="p-4 flex flex-col max-h-[40%] overflow-hidden border-b border-border-light dark:border-border-dark">
   277→      {/* Folders header */}
   278→      <div className="flex items-center justify-between mb-4 flex-shrink-0">
   279→        <h3 className="text-base font-semibold text-text-light-primary dark:text-text-dark-primary">Folders</h3>
   280→        <button
   281→          onClick={() => createFolder()}
   282→          className="text-xs px-3 h-8 bg-accent-blue hover:bg-accent-blue-hover text-white rounded transition-colors duration-150 font-medium"
   283→          title="New Folder"
   284→        >
   285→          + Folder
   286→        </button>
   287→      </div>
   288→
   289→      {/* Search Input */}
   290→      <div className="px-3 py-2">
   291→        <input
   292→          type="text"
   293→          placeholder="Search notes... (Cmd+K)"
   294→          className="w-full px-3 py-2 text-sm border border-border-light dark:border-border-dark rounded-lg
   295→                     bg-surface-light dark:bg-surface-dark
   296→                     text-text-light-primary dark:text-text-dark-primary
   297→                     placeholder-text-light-secondary dark:placeholder-text-dark-secondary
   298→                     focus:outline-none focus:ring-2 focus:ring-accent-blue transition-all"
   299→          value={searchQuery}
   300→          onChange={(e) => setSearchQuery(e.target.value)}
   301→          ref={searchInputRef}
   302→        />
   303→      </div>
   304→
   305→      {/* All Notes (root level) */}
   306→      {!searchQuery.trim() && (
   307→        <button
   308→          onClick={() => setActiveFolder(null)}
   309→          className={`w-full text-left px-3 h-8 rounded-lg transition-colors mb-1 flex-shrink-0 flex items-center text-base ${
   310→            activeFolderId === null
   311→              ? 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-primary dark:text-text-dark-primary font-medium'
   312→              : 'hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated text-text-light-secondary dark:text-text-dark-secondary'
   313→          }`}
   314→        >
   315→          📂 All Notes
   316→        </button>
   317→      )}
   318→
   319→      {/* Search Results OR Folder list */}
   320→      {searchQuery.trim() ? (
   321→        /* Search Results */
   322→        <div className="px-3 overflow-y-auto flex-1">
   323→          <h3 className="text-sm font-semibold text-text-light-secondary dark:text-text-dark-secondary mb-2">
   324→            {searchNotes(searchQuery).length} results for "{searchQuery}"
   325→          </h3>
   326→          <div className="space-y-2">
   327→            {searchNotes(searchQuery).map((note) => (
   328→              <div
   329→                key={note.id}
   330→                onClick={() => {
   331→                  setSearchQuery(''); // Clear search
   332→                  // Note will be selected via the NotesList component
   333→                }}
   334→                className="p-3 rounded-lg cursor-pointer hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-colors"
   335→              >
   336→                <div className="font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
   337→                  {note.title || 'Untitled'}
   338→                </div>
   339→                <div className="text-sm text-text-light-secondary dark:text-text-dark-secondary line-clamp-2">
   340→                  {note.contentText?.slice(0, 150)}...
   341→                </div>
   342→                <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary mt-1">
   343→                  {new Date(note.updatedAt).toLocaleDateString()}
   344→                </div>
   345→              </div>
   346→            ))}
   347→            {searchNotes(searchQuery).length === 0 && (
   348→              <div className="text-sm text-text-light-secondary dark:text-text-dark-secondary text-center py-8">
   349→                No notes found for "{searchQuery}"
   350→              </div>
   351→            )}
   352→          </div>
   353→        </div>
   354→      ) : (
   355→        /* Folder tree - Scrollable */
   356→        <div className="space-y-1 overflow-y-auto flex-1">
   357→          {folderTree.map((node) => (
   358→            <FolderTreeNode
   359→              key={node.id}
   360→              node={node}
   361→              depth={0}
   362→              activeFolderId={activeFolderId}
   363→              expandedFolderIds={expandedFolderIds}
   364→              onSelect={setActiveFolder}
   365→              onToggleExpanded={toggleExpanded}
   366→              onDelete={handleDeleteFolder}
   367→              onRename={handleRenameFolder}
   368→              getFolderNoteCount={getFolderNoteCount}
   369→            />
   370→          ))}
   371→
   372→          {/* Empty state */}
   373→          {folderTree.length === 0 && (
   374→            <div className="text-sm text-text-light-secondary dark:text-text-dark-secondary text-center py-4">
   375→              No folders yet
   376→            </div>
   377→          )}
   378→        </div>
   379→      )}
   380→
   381→      {/* Delete Folder Confirmation Dialog */}
   382→      <ConfirmDialog
   383→        isOpen={deleteDialogOpen}
   384→        onClose={() => setDeleteDialogOpen(false)}
   385→        onConfirm={confirmDeleteFolder}
   386→        title="Delete Folder"
   387→        message={`Delete folder "${selectedFolderName}"? This will also delete ${selectedFolderId ? getFolderNoteCount(selectedFolderId) : 0} note(s) inside.`}
   388→        confirmText="Delete"
   389→        variant="danger"
   390→      />
   391→
   392→      {/* Rename Folder Prompt Dialog */}
   393→      <PromptDialog
   394→        isOpen={renameDialogOpen}
   395→        onClose={() => setRenameDialogOpen(false)}
   396→        onConfirm={confirmRenameFolder}
   397→        title="Rename Folder"
   398→        message="Enter a new name for this folder:"
   399→        defaultValue={selectedFolderName}
   400→        placeholder="Folder name"
   401→        confirmText="Rename"
   402→      />
   403→    </div>
   404→  );
   405→};
   406→
   407→/**
   408→ * Note List Item Component
   409→ */
   410→const NoteListItem: React.FC<{ note: Note; isActive: boolean }> = ({
   411→  note,
   412→  isActive,
   413→}) => {
   414→  const setActiveNote = useNotesStore((state) => state.setActiveNote);
   415→  const deleteNote = useNotesStore((state) => state.deleteNote);
   416→  const togglePin = useNotesStore((state) => state.togglePin);
   417→  const toggleFavorite = useNotesStore((state) => state.toggleFavorite);
   418→  const [showDeleteDialog, setShowDeleteDialog] = useState(false);
   419→  const [isExporting, setIsExporting] = useState(false);
   420→  const [exportSuccess, setExportSuccess] = useState<string | null>(null);
   421→
   422→  // Handle PDF export with loading state
   423→  const handlePDFExport = async (e: React.MouseEvent) => {
   424→    e.stopPropagation();
   425→    setIsExporting(true);
   426→    try {
   427→      await exportNoteToPDF(note, (filename) => {
   428→        setExportSuccess(filename);
   429→        setTimeout(() => setExportSuccess(null), 3000); // Clear after 3s
   430→      });
   431→    } catch (error) {
   432→      log.error('PDF export failed', { error });
   433→    } finally {
   434→      setIsExporting(false);
   435→    }
   436→  };
   437→
   438→  // Format date
   439→  const formatDate = (date: Date) => {
   440→    const now = new Date();
   441→    const diff = now.getTime() - new Date(date).getTime();
   442→    const days = Math.floor(diff / (1000 * 60 * 60 * 24));
   443→
   444→    if (days === 0) return 'Today';
   445→    if (days === 1) return 'Yesterday';
   446→    if (days < 7) return `${days} days ago`;
   447→    return new Date(date).toLocaleDateString();
   448→  };
   449→
   450→  // First line of content
   451→  const preview = note.contentText.split('\n')[0] || 'No content';
   452→
   453→  return (
   454→    <div
   455→      className={`group relative p-3 rounded-lg cursor-pointer transition-all ${
   456→        isActive
   457→          ? 'bg-primary-cyan bg-opacity-10 border-l-4 border-primary-cyan'
   458→          : 'hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated border-l-4 border-transparent'
   459→      }`}
   460→      onClick={() => setActiveNote(note.id)}
   461→    >
   462→      {/* Pin/Favorite indicators */}
   463→      <div className="absolute top-2 right-2 flex gap-1">
   464→        {note.isFavorite && <div className="text-amber-500">⭐</div>}
   465→        {note.isPinned && <div className="text-amber-500">📌</div>}
   466→      </div>
   467→
   468→      {/* Title */}
   469→      <h4 className="font-medium text-text-light-primary dark:text-text-dark-primary mb-1 pr-6 truncate">
   470→        {note.title}
   471→      </h4>
   472→
   473→      {/* Preview */}
   474→      <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary line-clamp-2 mb-2">
   475→        {preview}
   476→      </p>
   477→
   478→      {/* Meta */}
   479→      <div className="flex items-center justify-between text-xs text-text-light-secondary dark:text-text-dark-secondary">
   480→        <span>{formatDate(note.updatedAt)}</span>
   481→        {note.tags.length > 0 && (
   482→          <span className="truncate ml-2">🏷️ {note.tags[0]}</span>
   483→        )}
   484→      </div>
   485→
   486→      {/* Export Success Notification */}
   487→      {exportSuccess && (
   488→        <div className="absolute -top-8 left-0 right-0 bg-green-500 text-white text-xs py-1 px-2 rounded shadow-lg z-10 text-center">
   489→          ✓ Exported: {exportSuccess}
   490→        </div>
   491→      )}
   492→
   493→      {/* Actions (show on hover) */}
   494→      <div className="absolute top-2 right-8 opacity-0 group-hover:opacity-100 transition-opacity flex gap-1">
   495→        <button
   496→          onClick={(e) => {
   497→            e.stopPropagation();
   498→            exportNoteToMarkdown(note);
   499→          }}
   500→          className="p-1 hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated rounded"
   501→          title="Export to Markdown"
   502→        >
   503→          ⬇️
   504→        </button>
   505→        <button
   506→          onClick={handlePDFExport}
   507→          disabled={isExporting}
   508→          className="p-1 hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated rounded disabled:opacity-50 disabled:cursor-not-allowed"
   509→          title={isExporting ? 'Exporting...' : 'Export to PDF'}
   510→        >
   511→          {isExporting ? '⏳' : '📄'}
   512→        </button>
   513→        <button
   514→          onClick={(e) => {
   515→            e.stopPropagation();
   516→            toggleFavorite(note.id);
   517→          }}
   518→          className="p-1 hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated rounded"
   519→          title={note.isFavorite ? 'Unfavorite' : 'Favorite'}
   520→        >
   521→          {note.isFavorite ? '⭐' : '☆'}
   522→        </button>
   523→        <button
   524→          onClick={(e) => {
   525→            e.stopPropagation();
   526→            togglePin(note.id);
   527→          }}
   528→          className="p-1 hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated rounded"
   529→          title={note.isPinned ? 'Unpin' : 'Pin'}
   530→        >
   531→          📌
   532→        </button>
   533→        <button
   534→          onClick={(e) => {
   535→            e.stopPropagation();
   536→            setShowDeleteDialog(true);
   537→          }}
   538→          className="p-1 hover:bg-red-100 dark:hover:bg-red-900 rounded text-red-600"
   539→          title="Delete"
   540→        >
   541→          🗑️
   542→        </button>
   543→      </div>
   544→
   545→      {/* Delete Confirmation Dialog */}
   546→      {showDeleteDialog && (
   547→        <ConfirmDialog
   548→          isOpen={true}
   549→          onClose={() => setShowDeleteDialog(false)}
   550→          onConfirm={() => {
   551→            deleteNote(note.id);
   552→            setShowDeleteDialog(false);
   553→          }}
   554→          title="Delete Note"
   555→          message={`Are you sure you want to delete "${note.title}"? This action cannot be undone.`}
   556→          variant="danger"
   557→        />
   558→      )}
   559→    </div>
   560→  );
   561→};
   562→
   563→/**
   564→ * Notes List Component
   565→ */
   566→const NotesList: React.FC = () => {
   567→  const activeFolderId = useFoldersStore((state) => state.activeFolderId);
   568→  // Get raw notes and store config (stable references)
   569→  const notesObj = useNotesStore((state) => state.notes);
   570→  const sortConfig = useNotesStore((state) => state.sortConfig);
   571→  const filter = useNotesStore((state) => state.filter);
   572→  const activeNoteId = useNotesStore((state) => state.activeNoteId);
   573→  const createNote = useNotesStore((state) => state.createNote);
   574→
   575→  // Compute filtered/sorted notes with useMemo
   576→  const notes = useMemo(() => {
   577→    // Filter by folder
   578→    // If activeFolderId is null, show ALL notes (not just notes with null folderId)
   579→    let filtered = activeFolderId === null
   580→      ? Object.values(notesObj) // Show all notes when "All Notes" is selected
   581→      : Object.values(notesObj).filter((note) => note.folderId === activeFolderId);
   582→
   583→    // Apply filter (archived, pinned, favorites, etc.)
   584→    switch (filter) {
   585→      case 'favorites':
   586→        filtered = filtered.filter((note) => note.isFavorite);
   587→        break;
   588→      case 'pinned':
   589→        filtered = filtered.filter((note) => note.isPinned);
   590→        break;
   591→      case 'archived':
   592→        filtered = filtered.filter((note) => note.isArchived);
   593→        break;
   594→      case 'unarchived':
   595→        filtered = filtered.filter((note) => !note.isArchived);
   596→        break;
   597→    }
   598→
   599→    // Sort notes
   600→    const sorted = [...filtered].sort((a, b) => {
   601→      let comparison = 0;
   602→      switch (sortConfig.field) {
   603→        case 'title':
   604→          comparison = a.title.localeCompare(b.title);
   605→          break;
   606→        case 'createdAt':
   607→          comparison = a.createdAt.getTime() - b.createdAt.getTime();
   608→          break;
   609→        case 'updatedAt':
   610→          comparison = a.updatedAt.getTime() - b.updatedAt.getTime();
   611→          break;
   612→      }
   613→      return sortConfig.order === 'asc' ? comparison : -comparison;
   614→    });
   615→
   616→    // Always pin pinned notes to top
   617→    return sorted.sort((a, b) => {
   618→      if (a.isPinned && !b.isPinned) return -1;
   619→      if (!a.isPinned && b.isPinned) return 1;
   620→      return 0;
   621→    });
   622→  }, [notesObj, activeFolderId, sortConfig, filter]);
   623→
   624→  return (
   625→    <div className="flex-1 overflow-y-auto">
   626→      <div className="bento-card p-4 m-3">
   627→        {/* Notes header */}
   628→        <div className="flex items-center justify-between mb-4">
   629→          <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary">
   630→            Notes ({notes.length})
   631→          </h3>
   632→          <button
   633→            onClick={() => createNote({ folderId: activeFolderId })}
   634→            className="px-3 py-1.5 bg-gradient-button-primary text-white rounded-lg hover:shadow-glow-magenta transition-all duration-200 text-sm font-medium"
   635→          >
   636→            + New Note
   637→          </button>
   638→        </div>
   639→
   640→      {/* Notes list */}
   641→      <div className="space-y-2">
   642→        {notes.map((note) => (
   643→          <NoteListItem
   644→            key={note.id}
   645→            note={note}
   646→            isActive={note.id === activeNoteId}
   647→          />
   648→        ))}
   649→      </div>
   650→
   651→      {/* Empty state */}
   652→      {notes.length === 0 && (
   653→        <div className="text-center py-12">
   654→          <div className="text-6xl mb-4">📝</div>
   655→          <h3 className="text-xl font-semibold text-text-light-primary dark:text-text-dark-primary mb-2">
   656→            No notes yet
   657→          </h3>
   658→          <p className="text-text-light-secondary dark:text-text-dark-secondary mb-4">
   659→            Create your first note to get started
   660→          </p>
   661→          <button
   662→            onClick={() => createNote({ folderId: activeFolderId })}
   663→            className="px-4 py-2 bg-gradient-button-primary text-white rounded-lg hover:shadow-glow-magenta transition-all duration-200 font-medium"
   664→          >
   665→            Create Note
   666→          </button>
   667→        </div>
   668→      )}
   669→      </div>
   670→    </div>
   671→  );
   672→};
   673→
   674→/**
   675→ * Notes Page Component
   676→ */
   677→export const Notes: React.FC = () => {
   678→  const activeNoteId = useNotesStore((state) => state.activeNoteId);
   679→  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
   680→
   681→  useEffect(() => {
   682→    document.title = 'Notes - Neuman Brain';
   683→    log.debug('Notes page loaded');
   684→  }, []);
   685→
   686→  return (
   687→    <div className="notes-page">
   688→      {/* Page Header */}
   689→      <PageHeader
   690→        title="Notes"
   691→        subtitle="Your second brain for ideas, thoughts, and knowledge"
   692→      />
   693→
   694→      {/* Notes Content */}
   695→      <div className="h-[calc(100vh-280px)] flex gap-8 relative">
   696→        {/* Sidebar toggle button */}
   697→        <button
   698→          onClick={() => setIsSidebarCollapsed(!isSidebarCollapsed)}
   699→          className="absolute left-0 top-4 z-20 p-2 bg-surface-light dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-r-lg hover:bg-surface-light-elevated dark:hover:bg-neutral-800 transition-all duration-200"
   700→          title={isSidebarCollapsed ? 'Show Sidebar' : 'Hide Sidebar'}
   701→          style={{ transform: isSidebarCollapsed ? 'translateX(0)' : 'translateX(0)' }}
   702→        >
   703→          {isSidebarCollapsed ? '→' : '←'}
   704→        </button>
   705→
   706→        {/* Left Sidebar - Folders + Notes List */}
   707→        <AnimatePresence>
   708→        {!isSidebarCollapsed && (
   709→          <motion.div
   710→            initial={{ width: 0, opacity: 0 }}
   711→            animate={{ width: 320, opacity: 1 }}
   712→            exit={{ width: 0, opacity: 0 }}
   713→            transition={{ duration: 0.2 }}
   714→            className="flex-shrink-0 border-r border-border-light dark:border-border-dark bg-transparent flex flex-col overflow-hidden"
   715→          >
   716→            <FolderSidebar />
   717→            <NotesList />
   718→          </motion.div>
   719→        )}
   720→      </AnimatePresence>
   721→
   722→      {/* Center - Editor */}
   723→      <div className="flex-1 overflow-hidden">
   724→        <div className="h-full overflow-hidden border border-border-light dark:border-border-dark rounded-lg">
   725→          {activeNoteId ? (
   726→            <NotesEditor noteId={activeNoteId} />
   727→          ) : (
   728→            <NotesEditorEmpty />
   729→          )}
   730→        </div>
   731→      </div>
   732→
   733→      {/* Right Sidebar - Metadata (Future) */}
