    94→        title={isCollapsed ? item.label : undefined}
    95→      >
    96→        {/* Active indicator (left accent) */}
    97→        {isActive && (
    98→          <div className="absolute left-0 top-2 bottom-2 w-[3px] bg-accent-blue rounded-r" />
    99→        )}
   100→
   101→        {/* Icon - Fixed 20px size */}
